    #[tokio::test]
    async fn minimax_stream_request_keeps_system_message_in_messages_array() {
        let sse = "data: {\"choices\":[{\"delta\":{\"content\":\"ok\"},\"finish_reason\":null}]}\n\n\
                   data: [DONE]\n\n";
